const { SecretClient } = require('@azure/keyvault-secrets');
const { DefaultAzureCredential } = require('@azure/identity');

// Initialize Key Vault client with Managed Identity
const credential = new DefaultAzureCredential();
const vaultUrl = process.env.AZURE_KEYVAULT_URL; // e.g., https://my-vault.vault.azure.net
const client = new SecretClient(vaultUrl, credential);

// Retrieve JWT secret at application startup
let jwtSecret;

async function initializeApp() {
  try {
    const secret = await client.getSecret('jwt-secret');
    jwtSecret = secret.value;
    console.log('JWT secret loaded from Key Vault');
  } catch (error) {
    console.error('Failed to retrieve secret from Key Vault:', error);
    process.exit(1); // Fail-fast if secret cannot be retrieved
  }
}

// Use in JWT middleware
const jwt = require('jsonwebtoken');

function generateToken(userId) {
  return jwt.sign(
    { userId, iat: Math.floor(Date.now() / 1000) },
    jwtSecret,
    { algorithm: 'HS256', expiresIn: '1h' }
  );
}

function verifyToken(token) {
  return jwt.verify(token, jwtSecret, { algorithms: ['HS256'] });
}

