const privateKey = fs.readFileSync('/var/secrets/jwt-private.pem', 'utf8');
const publicKey = fs.readFileSync('/var/secrets/jwt-public.pem', 'utf8');

// Sign tokens with private key (auth service only)
function generateToken(userId) {
  return jwt.sign(
    { userId, iat: Math.floor(Date.now() / 1000) },
    privateKey,
    { algorithm: 'RS256', expiresIn: '1h' }
  );
}

// Verify tokens with public key (all services can do this)
function verifyToken(token) {
  return jwt.verify(token, publicKey, { algorithms: ['RS256'] });
}

// Middleware for protected routes
function authenticateJWT(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = verifyToken(token);
    req.user = decoded;
    next();
  } catch (error) {
    return res.status(403).json({ error: 'Invalid token' });
  }
}
